+        let signing_key = Ed25519SigningKey::generate();
+        let genesis = GenesisState::create_deterministic(&signing_key.verifying_key());
+        let cbor = genesis.to_cbor().unwrap();
+        let restored = GenesisState::from_cbor(&cbor).unwrap();
